def spirv_named_ids(spv_code, name):
    return re.findall(rf'OpName (%\d+) "{re.escape(name)}"', spv_code)


def spirv_named_id(spv_code, name):
    ids = spirv_named_ids(spv_code, name)
    assert ids, f"Missing OpName for {name}"
    return ids[0]


def spirv_named_variable(spv_code, name, pointer_type=None, storage_class=None):
    pointer_pattern = re.escape(pointer_type) if pointer_type else r"%\d+"
    storage_pattern = storage_class if storage_class else r"\w+"
    for variable_id in spirv_named_ids(spv_code, name):
        if re.search(
            rf"{re.escape(variable_id)} = OpVariable {pointer_pattern} "
            rf"{storage_pattern}\b",
            spv_code,
        ):
            return variable_id
    raise AssertionError(f"Missing variable {name}")


def spirv_pointer_type(spv_code, pointee_type, storage_class):
    match = re.search(
        rf"(%\d+) = OpTypePointer {storage_class} {re.escape(pointee_type)}\b",
        spv_code,
    )
    assert match is not None
    return match.group(1)


def spirv_result_ids_for_opcode(spv_code, opcode):
    return re.findall(rf"(%\d+) = {re.escape(opcode)}\b", spv_code)


def assert_spirv_access_chain_indexes_are_integer(spv_code):
    int_types = set(re.findall(r"(%\d+) = OpTypeInt \d+ [01]\b", spv_code))
    result_types = {
        result_id: result_type
        for result_id, result_type in re.findall(r"(%\d+) = Op\w+ (%\d+)\b", spv_code)
    }

    for access_chain in re.findall(r"%\d+ = OpAccessChain %\d+ %\d+([^\n]*)", spv_code):
        for index_id in access_chain.split():
            assert result_types.get(index_id) in int_types


def spirv_uint_constant_values(spv_code):
    uint_types = set(re.findall(r"(%\d+) = OpTypeInt 32 0\b", spv_code))
    return {
        result_id: int(value)
        for result_id, type_id, value in re.findall(
            r"(%\d+) = OpConstant (%\d+) (-?\d+)\b", spv_code
        )
        if type_id in uint_types
    }


def spirv_vector_type_widths(spv_code):
    return {
        type_id: int(width)
        for type_id, width in re.findall(
            r"(%\d+) = OpTypeVector %\d+ ([234])\b", spv_code
        )
    }


def assert_vector_constructs_have_exact_scalar_operands(spv_code):
    vector_widths = spirv_vector_type_widths(spv_code)
    vector_values = {
        result_id
        for result_id, result_type in re.findall(r"(%\d+) = Op\w+ (%\d+)\b", spv_code)
        if result_type in vector_widths
    }

    for _, result_type, operands in re.findall(
        r"(%\d+) = OpCompositeConstruct (%\d+) ([^\n]+)",
        spv_code,
    ):
        if result_type not in vector_widths:
            continue

        operand_ids = operands.split()
        assert len(operand_ids) == vector_widths[result_type]
        assert not set(operand_ids) & vector_values


def assert_matrix_constructs_have_exact_column_operands(spv_code):
    matrix_types = {
        type_id: (column_type, int(column_count))
        for type_id, column_type, column_count in re.findall(
            r"(%\d+) = OpTypeMatrix (%\d+) (\d+)\b", spv_code
        )
    }
    result_types = {
        result_id: result_type
        for result_id, result_type in re.findall(r"(%\d+) = Op\w+ (%\d+)\b", spv_code)
    }

    for _, result_type, operands in re.findall(
        r"(%\d+) = OpCompositeConstruct (%\d+) ([^\n]+)",
        spv_code,
    ):
        if result_type not in matrix_types:
            continue

        column_type, column_count = matrix_types[result_type]
        operand_ids = operands.split()
        assert len(operand_ids) == column_count
        assert all(
            result_types.get(operand_id) == column_type for operand_id in operand_ids
        )


def assert_spirv_stores_use_matching_value_types(spv_code):
    result_types = {
        result_id: result_type
        for result_id, result_type in re.findall(r"(%\d+) = Op\w+ (%\d+)\b", spv_code)
    }
    pointer_pointees = {
        pointer_type: pointee_type
        for pointer_type, pointee_type in re.findall(
            r"(%\d+) = OpTypePointer \w+ (%\d+)\b", spv_code
        )
    }

    for pointer_id, value_id in re.findall(r"OpStore (%\d+) (%\d+)", spv_code):
        pointer_type = result_types.get(pointer_id)
        expected_type = pointer_pointees.get(pointer_type)
        actual_type = result_types.get(value_id)
        if expected_type is not None and actual_type is not None:
            assert actual_type == expected_type


def assert_spirv_function_calls_use_declared_parameter_types(spv_code):
    result_types = {
        result_id: result_type
        for result_id, result_type in re.findall(r"(%\d+) = Op\w+ (%\d+)\b", spv_code)
    }
    function_type_params = {
        function_type: params.split()
        for function_type, params in re.findall(
            r"(%\d+) = OpTypeFunction %\d+(?: ([^\n]+))?", spv_code
        )
    }
    function_declared_types = {
        function_id: function_type
        for function_id, function_type in re.findall(
            r"(%\d+) = OpFunction %\d+ \w+ (%\d+)\b", spv_code
        )
    }

    for callee_id, operand_text in re.findall(
        r"OpFunctionCall %\d+ (%\d+)([^\n]*)", spv_code
    ):
        function_type = function_declared_types.get(callee_id)
        if function_type is None:
            continue

        expected_types = function_type_params.get(function_type, [])
        operands = operand_text.split()
        assert len(operands) == len(expected_types)
        for operand_id, expected_type in zip(operands, expected_types):
            assert result_types.get(operand_id) == expected_type


def spirv_named_parameters(spv_code, name, pointer_type=None):
    pointer_pattern = re.escape(pointer_type) if pointer_type else r"%\d+"
    return [
        parameter_id
        for parameter_id in spirv_named_ids(spv_code, name)
        if re.search(
            rf"{re.escape(parameter_id)} = OpFunctionParameter {pointer_pattern}\b",
            spv_code,
        )
    ]


def spirv_named_parameter(spv_code, name, pointer_type=None):
    parameters = spirv_named_parameters(spv_code, name, pointer_type)
    assert parameters, f"Missing function parameter {name}"
    return parameters[0]


def assert_spirv_function_variables_are_first_block_declarations(spv_code):
    lines = spv_code.splitlines()
    function_start = None

    for index, line in enumerate(lines):
        if re.match(r"%\d+ = OpFunction\b", line):
            function_start = index
            continue

        if function_start is not None and line == "OpFunctionEnd":
            function_lines = lines[function_start : index + 1]
            first_label = next(
                i
                for i, function_line in enumerate(function_lines)
                if re.match(r"%\d+ = OpLabel\b", function_line)
            )
            first_non_variable = next(
                (
                    i
                    for i, function_line in enumerate(function_lines[first_label + 1 :])
                    if not re.match(r"%\d+ = OpVariable %\d+ Function\b", function_line)
                ),
                None,
            )
            if first_non_variable is None:
                first_non_variable = len(function_lines)
            else:
                first_non_variable += first_label + 1

            for variable_index, function_line in enumerate(function_lines):
                if re.match(r"%\d+ = OpVariable %\d+ Function\b", function_line):
                    assert first_label < variable_index < first_non_variable

            function_start = None


def test_glsl_input_attachment_lowers_to_spirv_subpass_data(tmp_path):
    shader = """
    #version 450
    layout(input_attachment_index = 3, set = 1, binding = 2)
    uniform subpassInput sceneColor;
    layout(location = 0) out vec4 fragColor;

    void main() {
        fragColor = subpassLoad(sceneColor);
    }
    """
    shader_path = tmp_path / "input-attachment.frag"
    shader_path.write_text(shader)

    generated = crosstl.translate(
        str(shader_path),
        backend="vulkan",
        format_output=False,
        source_backend="opengl",
    )

    scene_color_id = spirv_named_variable(
        generated, "sceneColor", storage_class="UniformConstant"
    )
    assert re.search(r"%\d+ = OpTypeImage %\d+ SubpassData 0 0 0 2 Unknown", generated)
    assert "OpTypePointer UniformConstant" in generated
    assert f"OpDecorate {scene_color_id} DescriptorSet 1" in generated
    assert f"OpDecorate {scene_color_id} Binding 2" in generated
    assert f"OpDecorate {scene_color_id} InputAttachmentIndex 3" in generated
    assert "OpImageRead" in generated
    assert "subpassLoad" not in generated
    assert "Unknown type subpassInput" not in generated


def assert_spirv_module_validates(spv_code, tmp_path, target_env=None):
    spirv_as = shutil.which("spirv-as")
    spirv_val = shutil.which("spirv-val")
    if not spirv_as or not spirv_val:
        pytest.skip("spirv-as and spirv-val are not installed")

    asm_path = tmp_path / "shader.spvasm"
    spv_path = tmp_path / "shader.spv"
    asm_path.write_text(spv_code)
    target_args = ["--target-env", target_env] if target_env else []

    assemble = subprocess.run(
        [spirv_as, *target_args, str(asm_path), "-o", str(spv_path)],
        capture_output=True,
        text=True,
        check=False,
    )
    assert assemble.returncode == 0, assemble.stderr

    validate = subprocess.run(
        [spirv_val, *target_args, str(spv_path)],
        capture_output=True,
        text=True,
        check=False,
    )
    assert validate.returncode == 0, validate.stderr


class TestSpirvType:
    def test_initialization(self):
        type1 = SpirvType("float")
        assert type1.base_type == "float"
        assert type1.storage_class is None
        assert str(type1) == "float"

        type2 = SpirvType("float", "Function")
        assert type2.base_type == "float"
        assert type2.storage_class == "Function"
        assert str(type2) == "float (Function)"


class TestSpirvId:
    def test_initialization(self):
        type1 = SpirvType("float")
        id1 = SpirvId(42, type1)
        assert id1.id == 42
        assert id1.type == type1
        assert id1.name is None
        assert str(id1) == "%42 (float)"

        id2 = SpirvId(43, type1, "my_var")
        assert id2.id == 43
        assert id2.type == type1
        assert id2.name == "my_var"
        assert str(id2) == "%43 (my_var: float)"


class TestVulkanSPIRVCodeGen:
    def assert_uint_int_min_literal_lowering(self, spv_code):
        signed_int_types = set(re.findall(r"(%\d+) = OpTypeInt 32 1\b", spv_code))
        signed_int_constants = {
            value
            for _, type_id, value in re.findall(
                r"(%\d+) = OpConstant (%\d+) (-?\d+)\b", spv_code
            )
            if type_id in signed_int_types
        }

        assert "2147483648" in {
            str(value) for value in spirv_uint_constant_values(spv_code).values()
        }
        assert "2147483648" not in signed_int_constants
        assert "OpSNegate" not in spv_code
        assert "OpISub" in spv_code
        assert "OpBitcast" in spv_code

    def test_signed_int_min_literal_lowers_through_unsigned_operand(self, tmp_path):
        source_code = """
        shader IntMinLiteral {
            compute {
                void main() {
                    int value = -2147483648;
                }
            }
        }
        """

        spv_code = VulkanSPIRVCodeGen().generate(
            Parser(Lexer(source_code).tokens).parse()
        )

        self.assert_uint_int_min_literal_lowering(spv_code)
        assert_spirv_module_validates(spv_code, tmp_path)

    def test_metal_unary_int_min_literal_translates_to_valid_spirv(self, tmp_path):
        source_path = tmp_path / "unary.metal"
        source_path.write_text(
            """
            #include <metal_stdlib>
            using namespace metal;

            kernel void unary_min_int() {
                int value = -2147483648;
            }
            """,
            encoding="utf-8",
        )

        spv_code = crosstl.translate(
            str(source_path), backend="vulkan", format_output=False
        )

        self.assert_uint_int_min_literal_lowering(spv_code)
        assert_spirv_module_validates(spv_code, tmp_path)

    def test_metal_bool_function_constant_lowers_to_spirv_spec_constant(self, tmp_path):
        source_path = tmp_path / "conv.metal"
        source_path.write_text(
            """
            #include <metal_stdlib>
            using namespace metal;

            constant bool do_flip [[function_constant(200)]];

            kernel void conv() {
                if (do_flip) {
                }
            }
            """,
            encoding="utf-8",
        )

        spv_code = crosstl.translate(
            str(source_path), backend="vulkan", format_output=False
        )
        bool_type = re.search(r"(%\d+) = OpTypeBool\b", spv_code)
        assert bool_type is not None
        do_flip = spirv_named_id(spv_code, "do_flip")

        assert f"{do_flip} = OpSpecConstantFalse {bool_type.group(1)}" in spv_code
        assert f"OpDecorate {do_flip} SpecId 200" in spv_code
        assert not re.search(rf"{re.escape(do_flip)} = OpVariable\b", spv_code)
        assert not re.search(
            rf"OpTypePointer (?:Input|Output) {re.escape(bool_type.group(1))}\b",
            spv_code,
        )
        assert_spirv_module_validates(spv_code, tmp_path)

    def test_metal_constant_bool_parameter_lowers_to_uniform_block(self, tmp_path):
        source_path = tmp_path / "random_reduced.metal"
        source_path.write_text(
            """
            #include <metal_stdlib>
            using namespace metal;

            kernel void random_reduced(
                device int* out [[buffer(0)]],
                constant const bool& odd) {
              out[0] = odd ? 1 : 0;
            }
            """,
            encoding="utf-8",
        )

        spv_code = crosstl.translate(
            str(source_path), backend="vulkan", format_output=False
        )
        bool_type = re.search(r"(%\d+) = OpTypeBool\b", spv_code)
        assert bool_type is not None
        odd_uniform = spirv_named_variable(
            spv_code, "oddUniform", storage_class="Uniform"
        )

        assert f"OpDecorate {odd_uniform} Binding" in spv_code
        assert "CrossGL_glcompute_input_odd" not in spv_code
        assert not re.search(
            rf"OpTypePointer Input {re.escape(bool_type.group(1))}\b",
            spv_code,
        )
        assert_spirv_module_validates(spv_code, tmp_path)

    def test_metal_constant_buffer_member_matrix_column_swizzle_lowers_to_spirv(
        self, tmp_path
    ):
        source_path = tmp_path / "apple_mesh_view_dir.metal"
        source_path.write_text(
            """
            #include <metal_stdlib>
            using namespace metal;

            struct Camera {
                float4x4 invViewMatrix;
            };

            struct VSOut {
                float4 position [[position]];
                float3 viewDir;
            };

            vertex VSOut apple_mesh(
                uint vertexID [[vertex_id]],
                constant Camera& camera [[buffer(1)]]
            ) {
                VSOut out;
                out.position = float4(0.0, 0.0, 0.0, 1.0);
                out.viewDir = camera.invViewMatrix[3].xyz;
                return out;
            }
            """,
            encoding="utf-8",
        )

        spv_code = crosstl.translate(
            str(source_path), backend="vulkan", format_output=False
        )

        camera_uniform = spirv_named_variable(
            spv_code, "cameraUniform", storage_class="Uniform"
        )
        assert f"OpDecorate {camera_uniform} Binding 1" in spv_code
        assert "Unknown type &Camera" not in spv_code
        assert "Could not find member invViewMatrix" not in spv_code
        assert (
            "Could not determine array element type for camera.invViewMatrix"
            not in spv_code
        )
        assert "Could not find member xyz" not in spv_code
        assert "WARNING" not in spv_code
        assert len(re.findall(r"%\d+ = OpAccessChain %\d+ %\d+ %\d+", spv_code)) >= 2
        assert_spirv_access_chain_indexes_are_integer(spv_code)
        assert re.search(r"%\d+ = OpVectorShuffle %\d+ %\d+ %\d+ 0 1 2", spv_code)
        assert_spirv_module_validates(spv_code, tmp_path)

    def test_vertex_index_array_access_uses_integer_access_chain_index(self, tmp_path):
        source_code = """
        shader VertexIndexArrayAccess {
            vertex {
                void main() {
                    vec2 positions[3] = {
                        vec2(0.0, -0.5),
                        vec2(0.5, 0.5),
                        vec2(-0.5, 0.5)
                    };
                    vec2 position = positions[gl_VertexIndex];
                    gl_Position = vec4(position, 0.0, 1.0);
                }
            }
        }
        """

        spv_code = VulkanSPIRVCodeGen().generate(
            Parser(Lexer(source_code).tokens).parse()
        )

        vertex_index = spirv_named_variable(
            spv_code, "gl_VertexIndex", storage_class="Input"
        )
        assert f"OpDecorate {vertex_index} BuiltIn VertexIndex" in spv_code
        assert "Unknown variable gl_VertexIndex" not in spv_code
        assert "WARNING" not in spv_code
        assert_spirv_access_chain_indexes_are_integer(spv_code)
        assert_spirv_module_validates(spv_code, tmp_path)

    def test_fallback_array_access_uses_integer_access_chain_index(self, tmp_path):
        source_code = """
        shader FallbackArrayIndex {
            compute {
                void main() {
                    float values[2] = { 1.0, 2.0 };
                    float value = values[missingIndex];
                }
            }
        }
        """

        spv_code = VulkanSPIRVCodeGen().generate(
            Parser(Lexer(source_code).tokens).parse()
        )

        assert "; WARNING: Unknown variable missingIndex" in spv_code
        assert_spirv_access_chain_indexes_are_integer(spv_code)
        assert_spirv_module_validates(spv_code, tmp_path)

    def test_compute_bool_input_lowers_to_uint_interface(self, tmp_path):
        source_code = """
        shader BoolInputLowering {
            compute {
                void main(bool flip) {
                    if (flip) {
                    }
                }
            }
        }
        """
        ast = Parser(Lexer(source_code).tokens).parse()
        spv_code = VulkanSPIRVCodeGen().generate(ast)

        bool_type = re.search(r"(%\d+) = OpTypeBool\b", spv_code)
        uint_type = re.search(r"(%\d+) = OpTypeInt 32 0\b", spv_code)
        assert bool_type is not None
        assert uint_type is not None

        interface_id = spirv_named_variable(
            spv_code, "CrossGL_glcompute_input_flip", storage_class="Input"
        )
        interface_variable = re.search(
            rf"{re.escape(interface_id)} = OpVariable (%\d+) Input\b", spv_code
        )
        assert interface_variable is not None
        assert (
            f"{interface_variable.group(1)} = OpTypePointer Input {uint_type.group(1)}"
            in spv_code
        )
        assert not re.search(
            rf"OpTypePointer Input {re.escape(bool_type.group(1))}\b", spv_code
        )
        assert re.search(
            rf"%\d+ = OpINotEqual {re.escape(bool_type.group(1))} %\d+ %\d+",
            spv_code,
        )
        assert "WARNING" not in spv_code
        assert_spirv_module_validates(spv_code, tmp_path)

    def test_compute_bool_vector_input_lowers_to_uint_vector_interface(self, tmp_path):
        source_code = """
        shader BoolVectorInputLowering {
            compute {
                void main(bvec2 flags) {
                    bool flip = flags.x;
                    if (flip) {
                    }
                }
            }
        }
        """
        spv_code = VulkanSPIRVCodeGen().generate(
            Parser(Lexer(source_code).tokens).parse()
        )

        bool_type = re.search(r"(%\d+) = OpTypeBool\b", spv_code)
        uint_type = re.search(r"(%\d+) = OpTypeInt 32 0\b", spv_code)
        assert bool_type is not None
        assert uint_type is not None

        bool_vec2 = re.search(
            rf"(%\d+) = OpTypeVector {re.escape(bool_type.group(1))} 2\b",
            spv_code,
        )
        uint_vec2 = re.search(
            rf"(%\d+) = OpTypeVector {re.escape(uint_type.group(1))} 2\b",
            spv_code,
        )
        assert bool_vec2 is not None
        assert uint_vec2 is not None

        interface_id = spirv_named_variable(
            spv_code, "CrossGL_glcompute_input_flags", storage_class="Input"
        )
        interface_variable = re.search(
            rf"{re.escape(interface_id)} = OpVariable (%\d+) Input\b", spv_code
        )
        assert interface_variable is not None
        assert (
            f"{interface_variable.group(1)} = OpTypePointer Input "
            f"{uint_vec2.group(1)}"
        ) in spv_code
        assert not re.search(
            rf"OpTypePointer Input {re.escape(bool_vec2.group(1))}\b", spv_code
        )
        assert re.search(
            rf"%\d+ = OpCompositeConstruct {re.escape(bool_vec2.group(1))} ",
            spv_code,
        )
        assert "WARNING" not in spv_code
        assert_spirv_module_validates(spv_code, tmp_path)

    def test_initialization(self):
        gen = VulkanSPIRVCodeGen()
        assert gen.next_id == 1
        assert gen.code_lines == []
        assert gen.primitive_types == {}
        assert gen.is_vertex_shader is False

    def test_get_id(self):
        gen = VulkanSPIRVCodeGen()
        assert gen.get_id() == 1
        assert gen.get_id() == 2
        assert gen.get_id() == 3
        assert gen.next_id == 4
        assert gen.bound_id == 3

    def test_emit(self):
        gen = VulkanSPIRVCodeGen()
        gen.emit("OpCapability Shader")
        gen.emit("OpMemoryModel Logical GLSL450")
        assert gen.code_lines == [
            "OpCapability Shader",
            "OpMemoryModel Logical GLSL450",
        ]

    def test_register_primitive_type(self):
        gen = VulkanSPIRVCodeGen()

        void_id = gen.register_primitive_type("void")
        assert void_id.id == 1
        assert void_id.type.base_type == "void"
        assert gen.primitive_types["void"] == void_id
        assert gen.code_lines[0] == "%1 = OpTypeVoid"

        float_id = gen.register_primitive_type("float")
        assert float_id.id == 2
        assert float_id.type.base_type == "float"
        assert gen.primitive_types["float"] == float_id
        assert gen.code_lines[1] == "%2 = OpTypeFloat 32"

        float_id2 = gen.register_primitive_type("float")
        assert float_id2.id == float_id.id

    def test_register_vector_type(self):
        gen = VulkanSPIRVCodeGen()
        float_id = gen.register_primitive_type("float")

        vec2_id = gen.register_vector_type(float_id, 2)
        assert vec2_id.id == 2
        assert vec2_id.type.base_type == "v2float"
        assert gen.code_lines[1] == "%2 = OpTypeVector %1 2"

        vec3_id = gen.register_vector_type(float_id, 3)
        assert vec3_id.id == 3
        assert vec3_id.type.base_type == "v3float"
        assert gen.code_lines[2] == "%3 = OpTypeVector %1 3"

        vec2_id2 = gen.register_vector_type(float_id, 2)
        assert vec2_id2.id == vec2_id.id

    def test_register_struct_type(self):
        gen = VulkanSPIRVCodeGen()
        float_id = gen.register_primitive_type("float")
        vec2_id = gen.register_vector_type(float_id, 2)

        members = [(float_id, "a"), (vec2_id, "b")]
        struct_id = gen.register_struct_type("MyStruct", members)

        assert struct_id.id == 3
        assert struct_id.type.base_type == "MyStruct"
        assert "%3 = OpTypeStruct %1 %2" in gen.code_lines
        assert 'OpName %3 "MyStruct"' in gen.code_lines
        assert 'OpMemberName %3 0 "a"' in gen.code_lines
        assert 'OpMemberName %3 1 "b"' in gen.code_lines

        assert gen.current_struct_members["MyStruct"] == members

    def test_register_pointer_type(self):
        gen = VulkanSPIRVCodeGen()
        float_id = gen.register_primitive_type("float")

        function_ptr = gen.register_pointer_type(float_id, "Function")
        assert function_ptr.id == 2
        assert function_ptr.type.base_type == "ptr_float"
        assert function_ptr.type.storage_class == "Function"
        assert gen.code_lines[1] == "%2 = OpTypePointer Function %1"

        input_ptr = gen.register_pointer_type(float_id, "Input")
        assert input_ptr.id == 3
        assert input_ptr.type.base_type == "ptr_float"
        assert input_ptr.type.storage_class == "Input"
        assert gen.code_lines[2] == "%3 = OpTypePointer Input %1"

        function_ptr2 = gen.register_pointer_type(float_id, "Function")
        assert function_ptr2.id == function_ptr.id

    def test_register_constant(self):
        gen = VulkanSPIRVCodeGen()
        float_id = gen.register_primitive_type("float")
        bool_id = gen.register_primitive_type("bool")

        const_id = gen.register_constant(3.14, float_id)
        assert const_id.id == 3
        assert const_id.type == float_id.type
        assert "%3 = OpConstant %1 3.14" in gen.code_lines

        another_const = gen.register_constant(2.71, float_id)
        assert another_const.id == 4
        assert "%4 = OpConstant %1 2.71" in gen.code_lines

        true_const = gen.register_constant(True, bool_id)
        false_const = gen.register_constant(False, bool_id)
        assert true_const.type == bool_id.type
        assert false_const.type == bool_id.type
        assert "%5 = OpConstantTrue %2" in gen.code_lines
        assert "%6 = OpConstantFalse %2" in gen.code_lines

    def test_create_variable(self):
        gen = VulkanSPIRVCodeGen()
        float_id = gen.register_primitive_type("float")

        var1 = gen.create_variable(float_id, "Function")
        assert var1.id == 3
        assert var1.type.storage_class == "Function"
        assert gen.code_lines[2] == "%3 = OpVariable %2 Function"

        var2 = gen.create_variable(float_id, "Input", "my_var")
        assert var2.id == 5
        assert var2.name == "my_var"
        assert gen.code_lines[4] == "%5 = OpVariable %4 Input"
        assert gen.code_lines[5] == 'OpName %5 "my_var"'

    def test_binary_operation(self):
        gen = VulkanSPIRVCodeGen()
        float_id = gen.register_primitive_type("float")
        left = gen.register_constant(1.0, float_id)
        right = gen.register_constant(2.0, float_id)

        result = gen.binary_operation("+", float_id, left, right)
        assert result.id == 4
        assert result.type == float_id.type
        assert "%4 = OpFAdd %1 %2 %3" in gen.code_lines

        result = gen.binary_operation("*", float_id, left, right)
        assert result.id == 5
        assert "%5 = OpFMul %1 %2 %3" in gen.code_lines

    def test_unary_operation(self):
        gen = VulkanSPIRVCodeGen()
        float_id = gen.register_primitive_type("float")
        operand = gen.register_constant(1.0, float_id)

        result = gen.unary_operation("-", float_id, operand)
        assert result.id == 3
        assert result.type == float_id.type
        assert "%3 = OpFNegate %1 %2" in gen.code_lines

        result = gen.unary_operation("+", float_id, operand)
        assert result.id == operand.id  # Should just return the operand

        int_id = gen.register_primitive_type("int")
        int_operand = gen.register_constant(1, int_id)
        result = gen.unary_operation("-", int_id, int_operand)
        assert result.type == int_id.type
        assert any("OpSNegate" in line for line in gen.code_lines)

    def test_process_expression(self):
        gen = VulkanSPIRVCodeGen()
        gen.register_primitive_type("float")

        result = gen.process_expression(1.0)
        assert isinstance(result, SpirvId)

        expr = BinaryOpNode(1.0, "+", 2.0)
        result = gen.process_expression(expr)
        assert isinstance(result, SpirvId)

    def test_simple_shader_generation(self):
        gen = VulkanSPIRVCodeGen()

        float_type = PrimitiveType("float")
        vec2_type = PrimitiveType("vec2")  # Simplified for test

        struct_members = [VariableNode("x", float_type), VariableNode("uv", vec2_type)]

        struct_node = StructNode("TestStruct", struct_members)

        function_body = BlockNode([ReturnNode()])

        function_node = FunctionNode(
            name="testFunction",
            return_type=float_type,
            parameters=[VariableNode("param", float_type)],
            body=function_body,
        )

        shader_node = ShaderNode(
            name="TestShader",
            execution_model=ExecutionModel.GRAPHICS_PIPELINE,
            structs=[struct_node],
            functions=[function_node],
            global_variables=[],
            constants=[],
        )

        spv_code = gen.generate(shader_node)

        assert "; SPIR-V" in spv_code
        assert "OpCapability Shader" in spv_code
        assert "OpMemoryModel Logical GLSL450" in spv_code
        assert "OpTypeStruct" in spv_code
        assert "OpFunction" in spv_code
        assert "OpReturn" in spv_code
        assert "OpFunctionEnd" in spv_code

    def test_bare_return_in_non_void_helper_emits_typed_default_return(self, tmp_path):
        source_code = """
        shader NonVoidBareReturn {
            compute {
                float fallback() {
                    return;
                }

                void main() {
                    float value = fallback();
                }
            }
        }
        """

        spv_code = VulkanSPIRVCodeGen().generate(
            Parser(Lexer(source_code).tokens).parse()
        )

        float_type = re.search(r"(%\d+) = OpTypeFloat 32\b", spv_code)
        assert float_type is not None
        helper = re.search(
            rf"(?P<function>%\d+) = OpFunction {re.escape(float_type.group(1))} "
            r"None %\d+\n(?P<body>.*?)OpFunctionEnd",
            spv_code,
            re.DOTALL,
        )
        assert helper is not None

        helper_body_lines = helper.group("body").splitlines()
        assert any(
            "Bare return in non-void function fallback" in line
            for line in helper_body_lines
        )
        assert any(line.startswith("OpReturnValue ") for line in helper_body_lines)
        assert "OpReturn" not in helper_body_lines
        assert re.search(
            rf"%\d+ = OpFunctionCall {re.escape(float_type.group(1))} "
            rf"{re.escape(helper.group('function'))}\s*$",
            spv_code,
            re.MULTILINE,
        )
        assert_spirv_module_validates(spv_code, tmp_path)

