    def test_generic_std450_lowering_registers_result_value_type(self):
        generator = VulkanSPIRVCodeGen()
        float_type = generator.register_primitive_type("float")
        vec2_type = generator.register_vector_type(float_type, 2)
        vec3_type = generator.register_vector_type(float_type, 3)
        zero = generator.register_constant(0.0, float_type)
        vector2 = generator.composite_construct(vec2_type, [zero, zero])
        vector3 = generator.composite_construct(vec3_type, [zero, zero, zero])

        sin_result = generator.call_builtin_function("sin", [vector2])
        atan2_result = generator.call_builtin_function("atan2", [vector2, vector2])
        cross_result = generator.call_builtin_function("cross", [vector3, vector3])
        code = "\n".join(generator.code_lines)

        assert sin_result is not None
        assert generator.value_types[sin_result.id] == vec2_type
        assert re.search(
            rf"%{sin_result.id} = OpExtInst %{vec2_type.id} %\d+ Sin %{vector2.id}",
            code,
        )
        assert atan2_result is not None
        assert generator.value_types[atan2_result.id] == vec2_type
        assert re.search(
            rf"%{atan2_result.id} = OpExtInst %{vec2_type.id} %\d+ "
            rf"Atan2 %{vector2.id} %{vector2.id}",
            code,
        )
        assert cross_result is not None
        assert generator.value_types[cross_result.id] == vec3_type
        assert re.search(
            rf"%{cross_result.id} = OpExtInst %{vec3_type.id} %\d+ "
            rf"Cross %{vector3.id} %{vector3.id}",
            code,
        )

    def test_bitcast_builtins_lower_aliases_and_register_result_types(self):
        generator = VulkanSPIRVCodeGen()
        float_type = generator.register_primitive_type("float")
        int_type = generator.register_primitive_type("int")
        uint_type = generator.register_primitive_type("uint")
        uvec2_type = generator.register_vector_type(uint_type, 2)

        float_value = generator.register_constant(1.0, float_type)
        int_value = generator.register_constant(1, int_type)
        uint_value = generator.register_constant(1, uint_type)
        uvec2_value = generator.composite_construct(
            uvec2_type, [uint_value, uint_value]
        )

        cases = [
            ("asfloat", uint_value, float_type),
            ("asint", float_value, int_type),
            ("asuint", float_value, uint_type),
            ("floatBitsToInt", float_value, int_type),
            ("floatBitsToUint", float_value, uint_type),
            ("intBitsToFloat", int_value, float_type),
            ("uintBitsToFloat", uint_value, float_type),
            (
                "asfloat",
                uvec2_value,
                generator.register_vector_type(float_type, 2),
            ),
        ]

        for function_name, operand, result_type in cases:
            result = generator.call_builtin_function(function_name, [operand])

            assert result is not None
            assert generator.value_types[result.id] == result_type
            assert (
                f"%{result.id} = OpBitcast %{result_type.id} %{operand.id}"
                in generator.code_lines
            )

    def test_bitcast_builtin_result_type_inference_preserves_vectors_and_shadowing(
        self,
    ):
        generator = VulkanSPIRVCodeGen()
        float_type = generator.register_primitive_type("float")
        uint_type = generator.register_primitive_type("uint")
        uvec2_type = generator.register_vector_type(uint_type, 2)
        vec2_type = generator.register_vector_type(float_type, 2)
        packed_var = generator.create_variable(uvec2_type, "Function", "packed")
        generator.local_variables["packed"] = packed_var

        inferred = generator.infer_expression_result_type(
            FunctionCallNode("asfloat", [IdentifierNode("packed")])
        )

        assert inferred == vec2_type

        user_function = SpirvId(999, SpirvType("function"), "asuint")
        generator.functions["asuint"] = user_function
        generator.function_signatures["asuint"] = (float_type, [float_type])

        shadowed = generator.infer_expression_result_type(
            FunctionCallNode("asuint", [IdentifierNode("packed")])
        )

        assert shadowed == float_type

    def test_integer_bit_builtins_lower_to_spirv_core_and_std450_ops(self, tmp_path):
        source_code = """
        shader SpirvIntegerBitBuiltins {
            compute {
                void main(uint3 tid @ gl_GlobalInvocationID) {
                    uvec3 mask = uvec3(tid.x, tid.y, tid.z);
                    int3 signedMask = int3(tid.x, tid.y, tid.z);
                    let counts = bitCount(mask);
                    let reversed = bitfieldReverse(mask);
                    let lowBits = findLSB(mask);
                    let unsignedHighBits = findMSB(mask);
                    let signedHighBits = findMSB(signedMask);
                    let aliasCount = countbits(tid.x);
                    let aliasReverse = reversebits(tid.y);
                    let aliasLow = firstbitlow(tid.z);
                    let aliasHigh = firstbithigh(tid.x);
                }
            }
        }
        """

        spv_code = VulkanSPIRVCodeGen().generate(
            Parser(Lexer(source_code).tokens).parse()
        )

        # SPIR-V core provides OpBitCount/OpBitReverse. GLSL.std.450 provides
        # FindILsb/FindSMsb/FindUMsb for least/most significant bit queries.
        assert "OpBitCount" in spv_code
        assert "OpBitReverse" in spv_code
        assert re.search(r"%\d+ = OpExtInst %\d+ %\d+ FindILsb %\d+", spv_code)
        assert re.search(r"%\d+ = OpExtInst %\d+ %\d+ FindUMsb %\d+", spv_code)
        assert re.search(r"%\d+ = OpExtInst %\d+ %\d+ FindSMsb %\d+", spv_code)
        assert "cannot lower unknown function" not in spv_code
        assert "WARNING" not in spv_code
        assert_spirv_module_validates(spv_code, tmp_path)

