    def test_fragment_discard_and_clip_lower_to_opkill(self, tmp_path):
        source_code = """
        shader FragmentDiscard {
            fragment {
                void main() {
                    float alpha = -0.5;
                    if (alpha < 0.0) {
                        discard;
                        float skipped = 1.0;
                    }
                    clip(alpha);
                    clip(vec3(1.0, -1.0, 2.0));
                }
            }
        }
        """

