    def test_integer_image_atomics_emit_spirv_atomic_operations(self, tmp_path):
        source_code = """
        shader ImageAtomics {
            uimage2D counters @r32ui;
            iimage2D signedCounters @r32i;
            uimage2DMS sampleCounters @r32ui;

            uint touchUnsigned(
                uimage2D image @r32ui,
                ivec2 pixel,
                uint value,
                uint replacement
            ) {
                uint added = imageAtomicAdd(image, pixel, value);
                uint minValue = imageAtomicMin(image, pixel, value);
                uint maxValue = imageAtomicMax(image, pixel, value);
                uint andValue = imageAtomicAnd(image, pixel, value);
                uint orValue = imageAtomicOr(image, pixel, value);
                uint xorValue = imageAtomicXor(image, pixel, value);
                uint exchanged = imageAtomicExchange(image, pixel, replacement);
                uint swapped = imageAtomicCompSwap(image, pixel, exchanged, value);
                return added
                    + minValue
                    + maxValue
                    + andValue
                    + orValue
                    + xorValue
                    + exchanged
                    + swapped;
            }

            int touchSigned(
                iimage2D image @r32i,
                ivec2 pixel,
                int value,
                int replacement
            ) {
                int minValue = imageAtomicMin(image, pixel, value);
                int maxValue = imageAtomicMax(image, pixel, value);
                int swapped = imageAtomicCompSwap(image, pixel, minValue, replacement);
                return minValue + maxValue + swapped;
            }

            uint touchSampled(
                uimage2DMS image @r32ui,
                ivec2 pixel,
                uint sample,
                uint value
            ) {
                uint added = imageAtomicAdd(image, pixel, sample, value);
                uint swapped =
                    imageAtomicCompSwap(image, pixel, sample, added, value);
                return added + swapped;
            }

            compute {
                void main() {
                    ivec2 pixel = ivec2(1, 2);
                    uint a = touchUnsigned(counters, pixel, 3u, 4u);
                    int b = touchSigned(signedCounters, pixel, -3, 4);
                    uint c = touchSampled(sampleCounters, pixel, 0u, 5u);
                }
            }
        }
        """

        spv_code = VulkanSPIRVCodeGen().generate(
            Parser(Lexer(source_code).tokens).parse()
        )

        assert "OpTypePointer Image" in spv_code
        assert spv_code.count("OpImageTexelPointer") == 13
        for operation in (
            "OpAtomicIAdd",
            "OpAtomicUMin",
            "OpAtomicUMax",
            "OpAtomicAnd",
            "OpAtomicOr",
            "OpAtomicXor",
            "OpAtomicExchange",
            "OpAtomicCompareExchange",
            "OpAtomicSMin",
            "OpAtomicSMax",
        ):
            assert operation in spv_code
        assert "imageAtomic" not in spv_code
        assert "WARNING" not in spv_code
        assert_spirv_module_validates(spv_code, tmp_path)

    def test_forwarded_r32_integer_image_atomics_validate_for_vulkan(self, tmp_path):
        source_code = """
        shader ForwardedImageAtomics {
            uimage2D counters @r32ui;
            iimage2D signedCounters @r32i;

            uint touchUnsignedLeaf(uimage2D image @r32ui, ivec2 pixel) {
                return imageAtomicAdd(image, pixel, 1u);
            }

            uint touchUnsignedForward(uimage2D image @r32ui, ivec2 pixel) {
                return touchUnsignedLeaf(image, pixel);
            }

            int touchSignedLeaf(iimage2D image @r32i, ivec2 pixel) {
                return imageAtomicMin(image, pixel, -1);
            }

            int touchSignedForward(iimage2D image @r32i, ivec2 pixel) {
                return touchSignedLeaf(image, pixel);
            }

            compute {
                void main() {
                    ivec2 pixel = ivec2(0, 1);
                    uint unsignedValue = touchUnsignedForward(counters, pixel);
                    int signedValue = touchSignedForward(signedCounters, pixel);
                }
            }
        }
        """

        spv_code = VulkanSPIRVCodeGen().generate(
            Parser(Lexer(source_code).tokens).parse()
        )

        uint_type = re.search(r"(%\d+) = OpTypeInt 32 0\b", spv_code)
        int_type = re.search(r"(%\d+) = OpTypeInt 32 1\b", spv_code)
        assert uint_type is not None
        assert int_type is not None
        assert f"OpTypeImage {uint_type.group(1)} 2D 0 0 0 2 R32ui" in spv_code
        assert f"OpTypeImage {int_type.group(1)} 2D 0 0 0 2 R32i" in spv_code
        assert spv_code.count("OpImageTexelPointer") == 2
        assert "OpAtomicIAdd" in spv_code
        assert "OpAtomicSMin" in spv_code
        assert "OpAtomicUMin" not in spv_code
        assert "WARNING" not in spv_code
        assert "imageAtomic" not in spv_code
        assert_spirv_module_validates(spv_code, tmp_path, target_env="vulkan1.0")

