    @pytest.mark.parametrize(
        ("source_code", "resource_name"),
        [
            (
                """
                shader Resources {
                    compute {
                        void main() {
                            sampler2d localMap;
                        }
                    }
                }
                """,
                "localMap",
            ),
            (
                """
                shader Resources {
                    vec4 sampleGrid(
                        sampler2d grids[][3],
                        int layer,
                        int slot,
                        vec2 uv
                    ) {
                        return texture(grids[layer][slot], uv);
                    }

                    compute {
                        void main() {
                            sampler2d localGrid[2][3];
                            vec2 uv = vec2(0.5, 0.25);
                            vec4 color = sampleGrid(localGrid, 1, 2, uv);
                        }
                    }
                }
                """,
                "localGrid",
            ),
            (
                """
                shader Resources {
                    compute {
                        void main() {
                            RWStructuredBuffer<float> localData;
                        }
                    }
                }
                """,
                "localData",
            ),
            (
                """
                shader Resources {
                    compute {
                        void main() {
                            accelerationStructureEXT localScene;
                        }
                    }
                }
                """,
                "localScene",
            ),
        ],
    )
    def test_function_local_descriptor_resources_raise_spirv_diagnostic(
        self, source_code, resource_name
    ):
        with pytest.raises(
            ValueError,
            match=(
                f"SPIR-V descriptor resource '{resource_name}' cannot be declared "
                "inside a function"
            ),
        ):
            VulkanSPIRVCodeGen().generate(Parser(Lexer(source_code).tokens).parse())

    def test_cbuffer_globals_emit_spirv_uniform_blocks_and_bindings(self):
        source_code = """
        shader UniformBlocks {
            cbuffer Camera @set(1) @binding(2) {
                mat4 viewProj;
                vec4 tint;
                float exposure;
                vec4 palette[2];
            }

            sampler2d colorMap;

            compute {
                void main() {
                    mat4 localView = viewProj;
                    vec4 color = tint * exposure + palette[1];
                    vec4 sampled = texture(colorMap, vec2(0.5, 0.5));
                    vec4 result = color + sampled;
                }
            }
        }
        """

        spv_code = VulkanSPIRVCodeGen().generate(
            Parser(Lexer(source_code).tokens).parse()
        )

        cbuffer_type = next(
            (
                type_id
                for type_id in spirv_named_ids(spv_code, "Camera")
                if re.search(rf"{re.escape(type_id)} = OpTypeStruct\b", spv_code)
            ),
            None,
        )
        assert cbuffer_type is not None
        cbuffer_var = spirv_named_variable(spv_code, "Camera", storage_class="Uniform")
        sampled_image = spirv_named_variable(
            spv_code, "colorMap", storage_class="UniformConstant"
        )

        assert f"OpDecorate {cbuffer_type} Block" in spv_code
        assert f"OpDecorate {cbuffer_var} DescriptorSet 1" in spv_code
        assert f"OpDecorate {cbuffer_var} Binding 2" in spv_code
        assert f"OpDecorate {sampled_image} DescriptorSet 0" in spv_code
        assert f"OpDecorate {sampled_image} Binding 0" in spv_code
        assert f"OpMemberDecorate {cbuffer_type} 0 Offset 0" in spv_code
        assert f"OpMemberDecorate {cbuffer_type} 0 ColMajor" in spv_code
        assert f"OpMemberDecorate {cbuffer_type} 0 MatrixStride 16" in spv_code
        assert f"OpMemberDecorate {cbuffer_type} 1 Offset 64" in spv_code
        assert f"OpMemberDecorate {cbuffer_type} 2 Offset 80" in spv_code
        assert f"OpMemberDecorate {cbuffer_type} 3 Offset 96" in spv_code
        assert re.search(r"OpDecorate %\d+ ArrayStride 16", spv_code)
        assert "OpAccessChain" in spv_code
        assert "Unknown variable" not in spv_code
        assert "WARNING" not in spv_code

    def test_uniform_struct_arrays_wrap_in_block_and_use_layout_bool(self, tmp_path):
        source_code = """
        shader UniformStructArray {
            struct Light {
                vec3 position;
                bool castsShadow;
            };

            uniform Light lights[4] @binding(2);

            compute {
                void main() {
                    Light light = lights[0];
                    if (light.castsShadow) {
                        vec3 position = light.position;
                    }
                }
            }
        }
        """

        spv_code = VulkanSPIRVCodeGen().generate(
            Parser(Lexer(source_code).tokens).parse()
        )

        bool_type = re.search(r"(%\d+) = OpTypeBool\b", spv_code)
        uint_type = re.search(r"(%\d+) = OpTypeInt 32 0\b", spv_code)
        layout_light = re.search(r'OpName (%\d+) "Light_std140_\d+"', spv_code)
        block_type = spirv_named_id(spv_code, "lightsBlock")
        lights_var = spirv_named_variable(spv_code, "lights", storage_class="Uniform")

        assert bool_type is not None
        assert uint_type is not None
        assert layout_light is not None
        layout_struct = re.search(
            rf"{re.escape(layout_light.group(1))} = OpTypeStruct "
            rf"(?P<members>[^\n]+)",
            spv_code,
        )
        assert layout_struct is not None
        assert uint_type.group(1) in layout_struct.group("members")
        assert bool_type.group(1) not in layout_struct.group("members")
        assert f"OpDecorate {block_type} Block" in spv_code
        assert f"OpDecorate {lights_var} Binding 2" in spv_code
        assert f"OpTypePointer Uniform {bool_type.group(1)}" not in spv_code
        assert re.search(
            rf"%\d+ = OpINotEqual {re.escape(bool_type.group(1))} %\d+ %\d+",
            spv_code,
        )
        assert "WARNING" not in spv_code
        assert_spirv_module_validates(spv_code, tmp_path, target_env="vulkan1.0")

