    def test_shadow_texture_compare_emits_dref_sampling(self):
        source_code = """
        shader Resources {
            sampler2dshadow shadowMap;
            sampler2dshadow shadowMaps[4];
            sampler compareSampler;

            float sampleLayer(sampler2DShadow maps[4], int layer, vec2 uv, float depth) {
                return textureCompare(maps[layer], uv, depth);
            }

            float sampleLayerWithSampler(
                sampler2DShadow maps[4],
                sampler compareSampler,
                int layer,
                vec2 uv,
                float depth
            ) {
                return textureCompare(maps[layer], compareSampler, uv, depth);
            }

            compute {
                void main() {
                    int layer = 1;
                    vec2 uv = vec2(0.25, 0.75);
                    float direct = textureCompare(shadowMap, uv, 0.5);
                    float indexed = textureCompare(
                        shadowMaps[layer],
                        compareSampler,
                        uv,
                        0.4
                    );
                    float helper = sampleLayer(shadowMaps, layer, uv, 0.3);
                    float helperSampler = sampleLayerWithSampler(
                        shadowMaps,
                        compareSampler,
                        layer,
                        uv,
                        0.2
                    );
                }
            }
        }
        """

        spv_code = VulkanSPIRVCodeGen().generate(
            Parser(Lexer(source_code).tokens).parse()
        )

        float_type = re.search(r"(%\d+) = OpTypeFloat 32", spv_code)
        shadow_image_type = re.search(
            r"%\d+ = OpTypeImage %\d+ 2D 1 0 0 1 Unknown",
            spv_code,
        )
        sampled_image_type = re.search(r"(%\d+) = OpTypeSampledImage %\d+", spv_code)
        assert float_type is not None
        assert shadow_image_type is not None
        assert sampled_image_type is not None

        array_type = re.search(
            rf"(%\d+) = OpTypeArray " rf"{re.escape(sampled_image_type.group(1))} %\d+",
            spv_code,
        )
        assert array_type is not None
        assert spv_code.count("OpImageSampleDrefExplicitLod") == 4
        assert f"OpImageSampleDrefExplicitLod {float_type.group(1)}" in spv_code
        assert "OpImageSampleImplicitLod" not in spv_code
        assert f"OpLoad {array_type.group(1)}" not in spv_code
        assert "textureCompare" not in spv_code
        assert "WARNING" not in spv_code

    def test_shadow_texture_compare_explicit_variants_emit_dref_operations(self):
        source_code = """
        shader Resources {
            sampler2dshadow shadowMap;
            sampler2dshadow shadowMaps[4];
            sampler compareSampler;

            float sampleLod(
                sampler2DShadow maps[4],
                sampler compareSampler,
                int layer,
                vec2 uv,
                float depth
            ) {
                return textureCompareLod(
                    maps[layer],
                    compareSampler,
                    uv,
                    depth,
                    1.0
                );
            }

            compute {
                void main() {
                    int layer = 1;
                    vec2 uv = vec2(0.25, 0.75);
                    vec2 dx = vec2(0.1, 0.0);
                    vec2 dy = vec2(0.0, 0.1);
                    ivec2 offset = ivec2(1, 0);
                    float lod = textureCompareLod(shadowMap, uv, 0.5, 2.0);
                    float lodOffset = textureCompareLodOffset(
                        shadowMap,
                        compareSampler,
                        uv,
                        0.45,
                        1.0,
                        offset
                    );
                    float grad = textureCompareGrad(
                        shadowMap,
                        compareSampler,
                        uv,
                        0.4,
                        dx,
                        dy
                    );
                    float gradOffset = textureCompareGradOffset(
                        shadowMap,
                        compareSampler,
                        uv,
                        0.35,
                        dx,
                        dy,
                        offset
                    );
                    float offsetShadow = textureCompareOffset(
                        shadowMaps[layer],
                        uv,
                        0.3,
                        offset
                    );
                    vec4 gathered = textureGatherCompare(shadowMap, uv, 0.6);
                    vec4 gatheredOffset = textureGatherCompareOffset(
                        shadowMaps[layer],
                        compareSampler,
                        uv,
                        0.2,
                        offset
                    );
                    float helper = sampleLod(
                        shadowMaps,
                        compareSampler,
                        layer,
                        uv,
                        0.1
                    );
                }
            }
        }
        """

        spv_code = VulkanSPIRVCodeGen().generate(
            Parser(Lexer(source_code).tokens).parse()
        )

        float_type = re.search(r"(%\d+) = OpTypeFloat 32", spv_code)
        sampled_image_type = re.search(r"(%\d+) = OpTypeSampledImage %\d+", spv_code)
        assert float_type is not None
        assert sampled_image_type is not None

        vec4_type = re.search(
            rf"(%\d+) = OpTypeVector {re.escape(float_type.group(1))} 4",
            spv_code,
        )
        array_type = re.search(
            rf"(%\d+) = OpTypeArray " rf"{re.escape(sampled_image_type.group(1))} %\d+",
            spv_code,
        )
        assert vec4_type is not None
        assert array_type is not None
        assert spv_code.count("OpImageSampleDrefExplicitLod") == 6
        assert spv_code.count("OpImageSampleDrefImplicitLod") == 0
        assert spv_code.count("OpImageDrefGather") == 2
        assert spv_code.count("OpCapability ImageGatherExtended") == 1
        assert "ConstOffset" not in spv_code
        assert (
            len(re.findall(r"\bOpImageSampleDrefExplicitLod\b.*\bOffset\b", spv_code))
            == 3
        )
        assert len(re.findall(r"\bOpImageDrefGather\b.*\bOffset\b", spv_code)) == 1
        assert f"OpImageSampleDrefExplicitLod {float_type.group(1)}" in spv_code
        assert f"OpImageSampleDrefImplicitLod {float_type.group(1)}" not in spv_code
        assert f"OpImageDrefGather {vec4_type.group(1)}" in spv_code
        assert re.search(
            r"OpImageSampleDrefExplicitLod %\d+ %\d+ %\d+ %\d+ Lod %\d+",
            spv_code,
        )
        assert re.search(
            r"OpImageSampleDrefExplicitLod %\d+ %\d+ %\d+ %\d+ Grad %\d+ %\d+",
            spv_code,
        )
        assert re.search(
            r"OpImageSampleDrefExplicitLod %\d+ %\d+ %\d+ %\d+ Lod\|Offset %\d+ %\d+",
            spv_code,
        )
        assert re.search(
            r"OpImageSampleDrefExplicitLod %\d+ %\d+ %\d+ %\d+ Grad\|Offset %\d+ %\d+ %\d+",
            spv_code,
        )
        assert f"OpLoad {array_type.group(1)}" not in spv_code
        assert "textureCompareLod" not in spv_code
        assert "textureCompareLodOffset" not in spv_code
        assert "textureCompareGrad" not in spv_code
        assert "textureCompareGradOffset" not in spv_code
        assert "textureCompareOffset" not in spv_code
        assert "textureGatherCompare" not in spv_code
        assert "textureGatherCompareOffset" not in spv_code
        assert "WARNING" not in spv_code

    def test_shadow_texture_compare_operations_reject_malformed_operands(
        self, tmp_path
    ):
        source_code = """
        shader Resources {
            sampler2d colorMap;
            sampler2dshadow shadowMap;
            samplerCubeShadow cubeShadow;

            compute {
                void main() {
                    float scalarCoord = 0.5;
                    vec2 uv = vec2(0.25, 0.75);
                    vec3 cubeCoord = vec3(1.0, 0.0, 0.0);
                    vec2 vectorDepth = vec2(0.5, 0.25);
                    vec2 vectorLod = vec2(1.0, 2.0);
                    vec2 grad = vec2(0.1, 0.0);
                    vec3 wideGrad = vec3(0.1, 0.0, 0.0);
                    ivec2 offset = ivec2(1, 0);
                    ivec3 wideOffset = ivec3(1, 0, 0);
                    vec2 floatOffset = vec2(1.0, 0.0);

                    float badResource = textureCompare(colorMap, uv, 0.5);
                    float badCoord = textureCompare(shadowMap, scalarCoord, 0.5);
                    float badDepth = textureCompare(shadowMap, uv, vectorDepth);
                    float badLod = textureCompareLod(
                        shadowMap,
                        uv,
                        0.5,
                        vectorLod
                    );
                    float badLodOffset = textureCompareLodOffset(
                        shadowMap,
                        uv,
                        0.5,
                        1.0,
                        wideOffset
                    );
                    float badGradX = textureCompareGrad(
                        shadowMap,
                        uv,
                        0.5,
                        scalarCoord,
                        grad
                    );
                    float badGradY = textureCompareGrad(
                        shadowMap,
                        uv,
                        0.5,
                        grad,
                        wideGrad
                    );
                    float badGradOffset = textureCompareGradOffset(
                        shadowMap,
                        uv,
                        0.5,
                        grad,
                        grad,
                        wideOffset
                    );
                    float badOffsetFloat = textureCompareOffset(
                        shadowMap,
                        uv,
                        0.5,
                        floatOffset
                    );
                    float badOffsetCube = textureCompareOffset(
                        cubeShadow,
                        cubeCoord,
                        0.5,
                        wideOffset
                    );
                    vec4 badGatherResource = textureGatherCompare(
                        colorMap,
                        uv,
                        0.5
                    );
                    vec4 badGatherCoord = textureGatherCompare(
                        shadowMap,
                        scalarCoord,
                        0.5
                    );
                    vec4 badGatherDepth = textureGatherCompare(
                        shadowMap,
                        uv,
                        vectorDepth
                    );
                    vec4 badGatherOffset = textureGatherCompareOffset(
                        shadowMap,
                        uv,
                        0.5,
                        wideOffset
                    );
                    vec4 badGatherCubeOffset = textureGatherCompareOffset(
                        cubeShadow,
                        cubeCoord,
                        0.5,
                        wideOffset
                    );
                }
            }
        }
        """

        spv_code = VulkanSPIRVCodeGen().generate(
            Parser(Lexer(source_code).tokens).parse()
        )

        for warning in [
            "; WARNING: textureCompare requires a shadow sampled image operand",
            "; WARNING: textureCompare requires a 2-component floating-point coordinate operand",
            "; WARNING: textureCompare requires a scalar floating-point depth operand",
            "; WARNING: textureCompareLod requires a scalar floating-point LOD operand",
            "; WARNING: textureCompareLodOffset requires a 2-component integer offset operand",
            "; WARNING: textureCompareGrad requires a 2-component floating-point dx gradient operand",
            "; WARNING: textureCompareGrad requires a 2-component floating-point dy gradient operand",
            "; WARNING: textureCompareGradOffset requires a 2-component integer offset operand",
            "; WARNING: textureCompareOffset requires a 2-component integer offset operand",
            "; WARNING: textureCompareOffset offsets are not valid for cube images",
            "; WARNING: textureGatherCompare requires a shadow sampled image operand",
            "; WARNING: textureGatherCompare requires a 2-component floating-point coordinate operand",
            "; WARNING: textureGatherCompare requires a scalar floating-point depth operand",
            "; WARNING: textureGatherCompareOffset requires a 2-component integer offset operand",
            "; WARNING: textureGatherCompareOffset offsets are not valid for cube images",
        ]:
            assert warning in spv_code

        for opcode in [
            "OpImageSampleDrefExplicitLod",
            "OpImageSampleDrefImplicitLod",
            "OpImageDrefGather",
        ]:
            assert opcode not in spv_code
        assert "OpCapability ImageGatherExtended" not in spv_code
        assert_spirv_stores_use_matching_value_types(spv_code)
        assert_spirv_module_validates(spv_code, tmp_path)

